//  OLD WAY: Constructor + Manual Prototype
function OldUser(name) { this.name = name; }
OldUser.prototype.login = function() { console.log('Logged in'); };

//  NEW WAY: ES6 Classes (Much cleaner!)
class NewUser {
  constructor(name) {
    this.name = name;
  }

  login() {
    console.log('Logged in');
  }
}

const user = new NewUser('Alice');
user.login();
